const headers = {} as IDataObject;
if (options.responseHeaders) {
	for (const header of (options.responseHeaders as IDataObject).entries as IDataObject[]) {
		if (typeof header.name !== 'string') {
			header.name = header.name?.toString();
		}
		headers[header.name?.toLowerCase() as string] = header.value?.toString();
	}
}

private setResponseHeaders(res: express.Response, headers?: WebhookResponseHeaders) {
	if (headers) {
		for (const [name, value] of headers.entries()) {
			res.setHeader(name, value);
		}
	}

export const isHtmlRenderedContentType = (contentType: string) => {
	const contentTypeLower = contentType.toLowerCase();

	return (
		// The content-type can also contain a charset, e.g. "text/html; charset=utf-8"
		contentTypeLower.startsWith('text/html') || contentTypeLower.startsWith('application/xhtml+xml')
	);

const contentType = res.getHeader('content-type') as string | undefined;
const needsSandbox = !contentType || isHtmlRenderedContentType(contentType);

if (needsSandbox && !isWebhookHtmlSandboxingDisabled()) {
	res.setHeader('Content-Security-Policy', getWebhookSandboxCSP());
}
